-- ── Lesson 1 ────────────────────────────────────────────────
UPDATE english_lesson_sections
SET content = $json${
  "title": "The History of Money: From Barter to Bitcoin",
  "text": "Money is one of the most transformative inventions in human history, yet it began simply as a solution to the inconvenience of barter. In early societies, people exchanged goods directly — a farmer might trade grain for a tool or an animal. This system had obvious limitations: both parties had to want exactly what the other had to offer, a problem economists call the double coincidence of wants. Commodity money — using valuable objects such as shells, salt, or grain as a medium of exchange — solved this problem. Eventually, metals such as gold and silver became the dominant commodity money because they were durable, portable, divisible, and relatively scarce. The minting of standardised coins by governments, beginning around 600 BCE in Lydia (modern Turkey), made trade far more efficient. Paper money emerged in China during the Tang Dynasty (618-907 CE) and reached Europe by the seventeenth century. Initially, paper money was a certificate that could be exchanged for a fixed quantity of gold or silver — a system known as the gold standard. This link was gradually severed over the twentieth century, and modern fiat currencies derive their value from government authority and public trust rather than any physical commodity. The invention of credit — borrowing money to spend now and repay later — dramatically expanded economic activity but also introduced new risks. Digital payments, online banking, and cryptocurrencies such as Bitcoin represent the latest phase in the evolution of money, enabling transactions across the world in seconds. As society becomes increasingly cashless, questions about financial inclusion — ensuring all members of society can participate in the digital economy — are becoming increasingly urgent.",
  "glossary": [
    {"term": "barter", "definition": "the direct exchange of goods or services without using money", "translation": "бартер"},
    {"term": "commodity money", "definition": "objects with intrinsic value used as a medium of exchange", "translation": "товарные деньги"},
    {"term": "fiat currency", "definition": "money that has value because a government declares it to be legal tender, not because it represents a commodity", "translation": "фиатная валюта"},
    {"term": "gold standard", "definition": "a monetary system where currency value is directly linked to a fixed amount of gold", "translation": "золотой стандарт"},
    {"term": "cryptocurrency", "definition": "a digital currency using cryptography for secure transactions without a central authority", "translation": "криптовалюта"},
    {"term": "financial inclusion", "definition": "ensuring that all people have access to useful and affordable financial products and services", "translation": "финансовая доступность"}
  ],
  "comprehension_questions": [
    {"id": 1, "question": "What problem with barter does the passage describe as the double coincidence of wants?", "options": ["A) The difficulty of agreeing on a fair price for goods", "B) The need for both parties to want exactly what the other has to offer", "C) The problem of transporting heavy goods over long distances", "D) The requirement that both parties speak the same language"], "answer": "B", "explanation": "The double coincidence of wants is the problem where both parties must want exactly what the other has to offer."},
    {"id": 2, "question": "Why did gold and silver become the dominant commodity money?", "options": ["A) Because they were the most beautiful materials available", "B) Because governments declared them to be official currencies", "C) Because they were durable, portable, divisible, and relatively scarce", "D) Because they were found everywhere in large quantities"], "answer": "C", "explanation": "Metals became dominant because they were durable, portable, divisible, and relatively scarce."},
    {"id": 3, "question": "What was the gold standard?", "options": ["A) A system where gold coins were the only accepted payment", "B) A monetary system where currency value was linked to a fixed amount of gold", "C) A quality standard for gold used in jewellery and coins", "D) An international agreement to use gold as a universal currency"], "answer": "B", "explanation": "The gold standard was a system where paper money was a certificate that could be exchanged for a fixed quantity of gold or silver."},
    {"id": 4, "question": "What do modern fiat currencies derive their value from?", "options": ["A) The gold reserves held by central banks", "B) The productivity of the national economy", "C) Government authority and public trust", "D) The silver and gold content of the currency"], "answer": "C", "explanation": "Modern fiat currencies derive their value from government authority and public trust rather than any physical commodity."},
    {"id": 5, "question": "What concern about digital payments and a cashless society does the passage raise?", "options": ["A) That digital payments are too slow to support global trade", "B) That cryptocurrencies will replace all traditional currencies", "C) That financial inclusion — ensuring all can participate — becomes more urgent", "D) That governments will lose the ability to control the money supply"], "answer": "C", "explanation": "As society becomes increasingly cashless, questions about financial inclusion and ensuring all members can participate are becoming more urgent."}
  ],
  "true_false_questions": [
    {"id": 1, "statement": "Barter is a more efficient system than money because it does not require trust in a government.", "answer": false, "evidence": "Barter had obvious limitations — both parties had to want exactly what the other had, a problem called the double coincidence of wants."},
    {"id": 2, "statement": "Standardised coins were first minted around 600 BCE in what is now Turkey.", "answer": true, "evidence": "The minting of standardised coins by governments, beginning around 600 BCE in Lydia (modern Turkey), made trade far more efficient."},
    {"id": 3, "statement": "Paper money was first used in Europe during the Middle Ages.", "answer": false, "evidence": "Paper money emerged in China during the Tang Dynasty (618-907 CE) and reached Europe by the seventeenth century."},
    {"id": 4, "statement": "The link between paper money and gold was maintained throughout the twentieth century.", "answer": false, "evidence": "This link was gradually severed over the twentieth century."},
    {"id": 5, "statement": "The invention of credit expanded economic activity but also introduced new risks.", "answer": true, "evidence": "The invention of credit dramatically expanded economic activity but also introduced new risks."}
  ],
  "vocabulary_in_context": [
    {"id": 1, "sentence": "In early societies, people exchanged goods directly without money — a system called [BLANK].", "options": ["A) barter", "B) trade", "C) commerce", "D) exchange"], "answer": "A", "explanation": "Barter is the specific term for the direct exchange of goods or services without using money."},
    {"id": 2, "sentence": "Paper money was initially a certificate exchangeable for a fixed quantity of gold — a system known as the [BLANK].", "options": ["A) silver standard", "B) commodity system", "C) gold standard", "D) fiat system"], "answer": "C", "explanation": "The gold standard is the monetary system where currency value was directly linked to a fixed amount of gold."},
    {"id": 3, "sentence": "Modern currencies like the US dollar are [BLANK] currencies — they have value because governments declare them legal tender, not because of any commodity backing.", "options": ["A) digital", "B) fiat", "C) credit", "D) commodity"], "answer": "B", "explanation": "Fiat currency derives its value from government authority and public trust, not from a physical commodity."},
    {"id": 4, "sentence": "Digital currencies using cryptography for secure transactions without central authority are called [BLANK].", "options": ["A) digital money", "B) e-currency", "C) cryptocurrencies", "D) virtual coins"], "answer": "C", "explanation": "Cryptocurrency is the specific term for digital currencies like Bitcoin that use cryptography and operate without a central authority."}
  ],
  "critical_thinking": [
    {"id": 1, "question": "The passage describes how money has evolved from physical commodities to digital currencies. What qualities should good money have? Does cryptocurrency meet these criteria?", "suggested_answer": "Good money should be durable, portable, divisible, scarce, and widely accepted as a medium of exchange. Cryptocurrencies like Bitcoin meet some of these criteria — they are divisible and portable — but their value is extremely volatile, which undermines their usefulness as a stable medium of exchange or store of value. They also require internet access and technical knowledge, limiting their use. Traditional currencies backed by stable governments and central banks tend to perform the functions of money more reliably for most people, though the technology underlying cryptocurrencies may eventually be applied in more stable forms."},
    {"id": 2, "question": "The passage raises the concern of financial inclusion as societies go cashless. Who is most at risk of being excluded, and what can be done to protect them?", "suggested_answer": "Those most at risk of exclusion from a cashless economy include elderly people who are less comfortable with digital technology, people living in poverty without smartphones or bank accounts, those in rural areas with poor internet connectivity, and undocumented migrants who cannot access formal banking. Solutions include maintaining cash as a legal option for payment, creating simple and free digital payment systems accessible by basic mobile phones, expanding banking access through post offices and community organisations, and providing digital literacy education to groups at risk of exclusion."}
  ]
}$json$::jsonb
WHERE lesson_id = (
  SELECT l.id FROM english_lessons l
  JOIN english_modules m ON l.module_id = m.id
  JOIN english_courses c ON m.course_id = c.id
  WHERE c.title = 'B1 Intermediate' AND c.category = 'General English'
    AND m.order_index = 4 AND l.order_index = 1
) AND type = 'reading';

-- ── Lesson 2 ────────────────────────────────────────────────
UPDATE english_lesson_sections
SET content = $json${
  "title": "The Rise of Consumerism: Buying More, Living Better?",
  "text": "Consumerism describes an economic and social system in which the acquisition of goods and services plays a central role in life and identity. While people have always bought and sold things, consumer culture as we know it today emerged in the twentieth century, driven by industrialisation, rising incomes, credit availability, and sophisticated advertising. The United States led this transformation. After World War Two, rising wages and the availability of consumer credit allowed millions of American families to buy homes, cars, televisions, and appliances for the first time. Manufacturers discovered that they could increase profits not simply by making better products but by making products that quickly became unfashionable or obsolete — a practice known as planned obsolescence. Advertising became a major industry dedicated to creating desire for things people had not previously known they needed. Consumer culture spread globally through the second half of the twentieth century, particularly accelerating after the end of the Cold War as previously restricted markets opened. Today, global consumption has reached levels that many economists and environmentalists consider unsustainable. The extraction of raw materials, the energy required for manufacturing and transportation, and the disposal of waste all place enormous pressure on natural systems. The fashion industry alone produces around ten percent of global carbon emissions. Critics of consumerism argue that beyond a certain level of comfort, additional consumption does not increase happiness or life satisfaction. Research in psychology consistently finds that experiences, social connections, and purpose contribute more to wellbeing than material possessions. Sustainable consumption — buying fewer, better-quality goods that last longer — is increasingly promoted as both an environmental and personal health imperative.",
  "glossary": [
    {"term": "consumerism", "definition": "a social and economic order encouraging the purchase of goods and services in ever-greater amounts", "translation": "консьюмеризм, потребительство"},
    {"term": "planned obsolescence", "definition": "the deliberate design of products to become outdated or unusable within a short period", "translation": "запланированное устаревание"},
    {"term": "acquisition", "definition": "the act of obtaining or buying something", "translation": "приобретение"},
    {"term": "obsolete", "definition": "no longer used or needed because something newer or better has replaced it", "translation": "устаревший"},
    {"term": "sustainable consumption", "definition": "using goods and services in a way that meets current needs without compromising future generations", "translation": "устойчивое потребление"},
    {"term": "wellbeing", "definition": "the state of being comfortable, healthy, and happy", "translation": "благополучие"}
  ],
  "comprehension_questions": [
    {"id": 1, "question": "What is consumerism as described in the passage?", "options": ["A) A system that prioritises saving money over spending it", "B) An economic and social system where acquiring goods is central to life and identity", "C) A government policy of subsidising consumer products", "D) The practice of buying only essential goods and services"], "answer": "B", "explanation": "Consumerism describes an economic and social system in which the acquisition of goods and services plays a central role in life and identity."},
    {"id": 2, "question": "What is planned obsolescence?", "options": ["A) A government programme to update public infrastructure", "B) The natural ageing and breakdown of products over time", "C) The deliberate design of products to become outdated quickly", "D) A marketing strategy to promote new products through advertising"], "answer": "C", "explanation": "Planned obsolescence is the practice of making products that quickly become unfashionable or obsolete to drive repeat purchases."},
    {"id": 3, "question": "What did manufacturers discover about increasing profits?", "options": ["A) Making better products always generates more profit", "B) Reducing prices attracts more customers than improving quality", "C) Making products that quickly become obsolete increases repeat purchases", "D) Advertising is less effective than word-of-mouth recommendation"], "answer": "C", "explanation": "Manufacturers discovered they could increase profits by making products that quickly became unfashionable or obsolete."},
    {"id": 4, "question": "What does research in psychology find about material possessions and happiness?", "options": ["A) More possessions consistently lead to greater happiness", "B) Experiences, connections, and purpose contribute more to wellbeing than possessions", "C) The relationship between possessions and happiness is the same across all cultures", "D) Only luxury goods contribute significantly to life satisfaction"], "answer": "B", "explanation": "Research consistently finds that experiences, social connections, and purpose contribute more to wellbeing than material possessions."},
    {"id": 5, "question": "What percentage of global carbon emissions does the fashion industry produce?", "options": ["A) Around two percent", "B) Around five percent", "C) Around ten percent", "D) Around fifteen percent"], "answer": "C", "explanation": "The fashion industry alone produces around ten percent of global carbon emissions."}
  ],
  "true_false_questions": [
    {"id": 1, "statement": "Consumer culture as we know it today has existed throughout all of human history.", "answer": false, "evidence": "Consumer culture as we know it today emerged in the twentieth century, driven by industrialisation, rising incomes, and advertising."},
    {"id": 2, "statement": "After World War Two, rising wages and consumer credit allowed American families to buy homes and appliances for the first time.", "answer": true, "evidence": "Rising wages and the availability of consumer credit allowed millions of American families to buy homes, cars, televisions, and appliances for the first time."},
    {"id": 3, "statement": "Global consumption has reached levels considered sustainable by most economists and environmentalists.", "answer": false, "evidence": "Today, global consumption has reached levels that many economists and environmentalists consider unsustainable."},
    {"id": 4, "statement": "Advertising was developed specifically to create desire for things people had not previously needed.", "answer": true, "evidence": "Advertising became a major industry dedicated to creating desire for things people had not previously known they needed."},
    {"id": 5, "statement": "Research consistently shows that buying more possessions is the most reliable path to happiness.", "answer": false, "evidence": "Research consistently finds that experiences, social connections, and purpose contribute more to wellbeing than material possessions."}
  ],
  "vocabulary_in_context": [
    {"id": 1, "sentence": "The economic and social system where the [BLANK] of goods is central to identity and daily life is called consumerism.", "options": ["A) production", "B) acquisition", "C) distribution", "D) regulation"], "answer": "B", "explanation": "Acquisition — the act of obtaining or buying something — is the word used in the passage's definition of consumerism."},
    {"id": 2, "sentence": "Manufacturers designed products to become quickly [BLANK] — no longer useful or fashionable — so customers would buy replacements sooner.", "options": ["A) expensive", "B) recyclable", "C) obsolete", "D) defective"], "answer": "C", "explanation": "Obsolete means no longer used or needed because something newer has replaced it."},
    {"id": 3, "sentence": "The practice of designing products to break or go out of fashion quickly is called planned [BLANK].", "options": ["A) consumption", "B) production", "C) obsolescence", "D) replacement"], "answer": "C", "explanation": "Planned obsolescence is the deliberate design of products to become outdated or unusable quickly."},
    {"id": 4, "sentence": "Buying fewer, better-quality goods that last longer is promoted as [BLANK] consumption — meeting needs without harming future generations.", "options": ["A) minimal", "B) responsible", "C) sustainable", "D) ethical"], "answer": "C", "explanation": "Sustainable consumption means using goods in a way that meets current needs without compromising future generations."}
  ],
  "critical_thinking": [
    {"id": 1, "question": "The passage describes planned obsolescence as a deliberate business strategy. Is this ethical? Should it be regulated or banned?", "suggested_answer": "Planned obsolescence raises genuine ethical concerns. Designing products to fail prematurely wastes resources, contributes to pollution, and financially exploits consumers by forcing unnecessary repeat purchases. It is particularly harmful in the context of the current environmental crisis, where extending the lifespan of products is essential for reducing waste and emissions. Regulating it — by requiring minimum product lifespans, mandating repairability, or banning software designed to degrade older devices — seems justified. Right-to-repair laws, which require manufacturers to provide spare parts and instructions, are one practical step already being taken in several countries."},
    {"id": 2, "question": "The passage suggests that beyond a certain level of comfort, consumption does not increase happiness. Why do people continue buying more if it does not make them happier?", "suggested_answer": "Several psychological mechanisms explain this gap between expectation and reality. Advertising is highly effective at creating aspirational desire, making us believe that the next purchase will finally satisfy us. Social comparison — comparing ourselves to neighbours, peers, or media images — drives consumption as a form of status signalling. Habit and routine make familiar consumption patterns feel normal and necessary. There is also genuine pleasure in the act of purchasing itself, which fades quickly once the item is owned — a phenomenon psychologists call hedonic adaptation. Understanding these mechanisms does not automatically change behaviour, but it can help people make more intentional choices."}
  ]
}$json$::jsonb
WHERE lesson_id = (
  SELECT l.id FROM english_lessons l
  JOIN english_modules m ON l.module_id = m.id
  JOIN english_courses c ON m.course_id = c.id
  WHERE c.title = 'B1 Intermediate' AND c.category = 'General English'
    AND m.order_index = 4 AND l.order_index = 2
) AND type = 'reading';

-- ── Lesson 3 ────────────────────────────────────────────────
UPDATE english_lesson_sections
SET content = $json${
  "title": "The Psychology of Advertising: How Brands Shape Decisions",
  "text": "Advertising is a multi-trillion dollar global industry whose purpose is to influence consumer behaviour. Modern advertising has moved far beyond simply informing people about products. It draws on psychology, neuroscience, data analysis, and behavioural economics to shape perceptions, create emotional associations, and influence decisions in ways that consumers often do not consciously recognise. One of the most powerful techniques is emotional branding. Rather than describing what a product does, advertisers create a lifestyle, feeling, or identity that the product represents. A sports drink does not just quench thirst — it represents athletic achievement and a healthy, active life. A luxury car is not simply transport — it signals success, taste, and social status. By associating products with aspirational identities, advertisers make purchasing feel like a step towards becoming the person you want to be. Social proof is another key psychological mechanism. People tend to follow the behaviour of others, particularly in uncertain situations. Advertisers exploit this through testimonials, celebrity endorsements, and statistics about how many millions of people use their product. The fear of missing out — sometimes called FOMO — is a related technique, creating urgency by suggesting that a deal is limited or that others are already benefiting. Digital advertising has made these techniques far more precise. Through data collected from social media, search engines, and online behaviour, advertisers can target individuals with messages specifically designed for their particular psychology, interests, and vulnerabilities. Critics argue that this level of personalised targeting, particularly directed at children and vulnerable individuals, raises serious ethical concerns about manipulation and consent. Media literacy — the ability to critically analyse and evaluate advertising messages — is increasingly regarded as an essential life skill.",
  "glossary": [
    {"term": "emotional branding", "definition": "a strategy of creating emotional associations between a product and a desired identity or feeling", "translation": "эмоциональный брендинг"},
    {"term": "social proof", "definition": "the tendency to follow the behaviour of others, used in advertising through testimonials and endorsements", "translation": "социальное доказательство"},
    {"term": "testimonial", "definition": "a statement by a customer or celebrity recommending a product", "translation": "отзыв, рекомендация"},
    {"term": "FOMO", "definition": "fear of missing out — anxiety that others are having rewarding experiences that you are not", "translation": "страх упустить что-то"},
    {"term": "media literacy", "definition": "the ability to critically analyse and evaluate media messages and advertising", "translation": "медиаграмотность"},
    {"term": "targeting", "definition": "the practice of directing advertising at specific individuals based on their characteristics and behaviour", "translation": "таргетирование"}
  ],
  "comprehension_questions": [
    {"id": 1, "question": "What is the purpose of emotional branding according to the passage?", "options": ["A) To describe the features and price of a product accurately", "B) To associate products with aspirational identities and feelings", "C) To compare a product favourably with its competitors", "D) To explain how a product is manufactured and tested"], "answer": "B", "explanation": "Emotional branding creates a lifestyle, feeling, or identity that the product represents, making purchasing feel like a step towards becoming who you want to be."},
    {"id": 2, "question": "What is social proof and how is it used in advertising?", "options": ["A) Evidence from scientific studies that a product is effective", "B) The tendency to follow others' behaviour, exploited through testimonials and endorsements", "C) A legal requirement to provide honest reviews of products", "D) A technique of comparing prices to show value"], "answer": "B", "explanation": "Social proof is the tendency to follow the behaviour of others, which advertisers exploit through testimonials, celebrity endorsements, and popularity statistics."},
    {"id": 3, "question": "What is FOMO as described in the passage?", "options": ["A) A technique for collecting consumer data through social media", "B) The fear of missing out, used to create urgency in advertising", "C) A psychological term for addiction to online shopping", "D) A form of targeted advertising based on personal data"], "answer": "B", "explanation": "FOMO — fear of missing out — is used to create urgency by suggesting that a deal is limited or others are already benefiting."},
    {"id": 4, "question": "How has digital advertising changed the use of psychological techniques?", "options": ["A) It has made advertising less personal and more generic", "B) It has reduced the effectiveness of emotional branding", "C) It allows precise targeting based on individual psychology, interests, and vulnerabilities", "D) It has made advertising less expensive and more ethical"], "answer": "C", "explanation": "Through data collected online, advertisers can target individuals with messages specifically designed for their particular psychology and vulnerabilities."},
    {"id": 5, "question": "What does the passage describe as an essential life skill?", "options": ["A) The ability to distinguish between good and bad advertising", "B) The ability to resist all forms of consumer marketing", "C) Media literacy — the ability to critically analyse advertising messages", "D) Understanding the legal regulations governing advertising"], "answer": "C", "explanation": "Media literacy — the ability to critically analyse and evaluate advertising messages — is increasingly regarded as an essential life skill."}
  ],
  "true_false_questions": [
    {"id": 1, "statement": "Modern advertising focuses primarily on providing factual information about product features.", "answer": false, "evidence": "Modern advertising has moved far beyond simply informing people about products — it creates emotional associations and influences decisions."},
    {"id": 2, "statement": "A luxury car advertisement is described in the passage as representing success and social status.", "answer": true, "evidence": "A luxury car is not simply transport — it signals success, taste, and social status."},
    {"id": 3, "statement": "Digital advertising targets all consumers with the same general message.", "answer": false, "evidence": "Advertisers can target individuals with messages specifically designed for their particular psychology, interests, and vulnerabilities."},
    {"id": 4, "statement": "Celebrity endorsements and testimonials are examples of social proof.", "answer": true, "evidence": "Advertisers exploit social proof through testimonials, celebrity endorsements, and statistics about how many millions use their product."},
    {"id": 5, "statement": "The passage argues that targeted advertising directed at children and vulnerable people raises no ethical concerns.", "answer": false, "evidence": "Critics argue that personalised targeting, particularly directed at children and vulnerable individuals, raises serious ethical concerns about manipulation and consent."}
  ],
  "vocabulary_in_context": [
    {"id": 1, "sentence": "Rather than describing a product, advertisers use [BLANK] to create emotional associations — making a sports drink represent athletic achievement.", "options": ["A) celebrity marketing", "B) emotional branding", "C) product placement", "D) targeted advertising"], "answer": "B", "explanation": "Emotional branding is the strategy of associating products with desired identities, feelings, and lifestyles."},
    {"id": 2, "sentence": "Advertisers use customer reviews, celebrity [BLANK], and popularity statistics to show that many people already trust and use their product.", "options": ["A) endorsements", "B) recommendations", "C) testimonials", "D) profiles"], "answer": "C", "explanation": "Testimonials are statements by customers or celebrities recommending a product, which is the specific word used in the passage."},
    {"id": 3, "sentence": "The anxiety that others are having rewarding experiences that you are missing — known as [BLANK] — is exploited to create urgency in advertising.", "options": ["A) peer pressure", "B) FOMO", "C) social anxiety", "D) consumer anxiety"], "answer": "B", "explanation": "FOMO stands for fear of missing out and is used by advertisers to make consumers act quickly."},
    {"id": 4, "sentence": "The ability to critically analyse and evaluate advertising messages is called [BLANK] and is increasingly considered an essential skill.", "options": ["A) consumer rights", "B) critical thinking", "C) media literacy", "D) digital awareness"], "answer": "C", "explanation": "Media literacy is the specific term used in the passage for the ability to analyse and evaluate media messages and advertising."}
  ],
  "critical_thinking": [
    {"id": 1, "question": "The passage raises concerns about targeted advertising directed at children. Should advertising to children be regulated more strictly or banned entirely? Give reasons.", "suggested_answer": "There are strong arguments for stricter regulation. Children have developing critical thinking skills and are particularly susceptible to emotional and aspirational appeals in advertising. They are also less able to recognise when they are being manipulated. Several countries have restricted advertising to children, particularly for junk food and toys. A complete ban would be difficult to enforce in the digital age, but clear restrictions on targeting children with personalised advertising based on data collection, combined with mandatory media literacy education, would be a more proportionate and practical approach than a complete prohibition."},
    {"id": 2, "question": "The passage argues that consumers are often influenced by advertising without consciously recognising it. Does this knowledge change how you think about your own purchasing decisions? What can individuals do to become more aware consumers?", "suggested_answer": "Awareness of advertising psychology can help people make more intentional choices, but it does not make us immune to its effects. Even people who know about social proof or emotional branding are still influenced by them, because these mechanisms operate partly at a subconscious level. Practical steps towards more aware consumption include waiting before purchasing to reduce impulse buying, questioning what emotional need a product is supposed to meet, and distinguishing between wants created by advertising and genuine needs. Developing media literacy — actively analysing rather than passively absorbing advertising — is the most effective long-term defence."}
  ]
}$json$::jsonb
WHERE lesson_id = (
  SELECT l.id FROM english_lessons l
  JOIN english_modules m ON l.module_id = m.id
  JOIN english_courses c ON m.course_id = c.id
  WHERE c.title = 'B1 Intermediate' AND c.category = 'General English'
    AND m.order_index = 4 AND l.order_index = 3
) AND type = 'reading';

-- ── Lesson 4 ────────────────────────────────────────────────
UPDATE english_lesson_sections
SET content = $json${
  "title": "The Online Shopping Revolution",
  "text": "The rise of e-commerce — buying and selling goods and services through the internet — has fundamentally transformed retail globally. In 1995, Amazon launched as an online bookstore. By 2023, it had become one of the most valuable companies in the world, selling almost everything imaginable, and online retail accounts for more than twenty percent of all retail sales in many developed countries. The convenience of online shopping is undeniable. Consumers can browse millions of products, read reviews, compare prices, and make purchases at any hour from any location with internet access. Delivery services have become faster — same-day or next-day delivery is now standard in many urban areas. Subscription services offer regular delivery of food, household products, and entertainment, reducing the need for planned shopping trips. However, the online retail revolution has had significant consequences for traditional high-street shops and city centres. Many large retailers, including long-established department stores and clothing chains, have closed hundreds of branches or gone out of business entirely as customer traffic moved online. City centres that once thrived on retail have been forced to reinvent themselves, converting empty shop spaces into residential units, entertainment venues, and community facilities. The environmental impact of e-commerce is complex. While physical retail requires energy-consuming buildings, online delivery creates its own emissions through the transportation of individual packages. The growth of packaging waste and the emissions from delivery vehicles represent significant challenges. Returns — which online shoppers make far more frequently than in-store shoppers — generate additional transportation emissions and waste. Meanwhile, gig economy workers who drive for delivery companies often face insecure employment, low pay, and minimal legal protections, raising serious questions about who bears the social costs of retail convenience.",
  "glossary": [
    {"term": "e-commerce", "definition": "the buying and selling of goods and services over the internet", "translation": "электронная коммерция"},
    {"term": "retail", "definition": "the sale of goods directly to consumers, typically in small quantities", "translation": "розничная торговля"},
    {"term": "subscription service", "definition": "a service providing regular delivery of products or access to content in exchange for periodic payment", "translation": "подписка"},
    {"term": "high street", "definition": "the main shopping street in a town or city; used to refer to traditional retail shops", "translation": "главная торговая улица"},
    {"term": "gig economy", "definition": "a labour market characterised by short-term contracts and freelance work rather than permanent employment", "translation": "гиг-экономика"},
    {"term": "returns", "definition": "goods sent back to the seller by the customer after purchase", "translation": "возврат товара"}
  ],
  "comprehension_questions": [
    {"id": 1, "question": "What was Amazon when it launched in 1995?", "options": ["A) A cloud computing company", "B) A digital payment platform", "C) An online bookstore", "D) A streaming entertainment service"], "answer": "C", "explanation": "Amazon launched in 1995 as an online bookstore before expanding into selling almost everything."},
    {"id": 2, "question": "What proportion of all retail sales does online shopping account for in many developed countries?", "options": ["A) Around five percent", "B) Around ten percent", "C) Around fifteen percent", "D) More than twenty percent"], "answer": "D", "explanation": "Online retail accounts for more than twenty percent of all retail sales in many developed countries."},
