  "true_false_questions": [
    {"id": 1, "statement": "Amazon was originally founded as a company selling a wide range of consumer products.", "answer": false, "evidence": "Amazon launched as an online bookstore in 1995 before expanding."},
    {"id": 2, "statement": "Online shopping allows consumers to browse and purchase at any time from any location with internet access.", "answer": true, "evidence": "Consumers can make purchases at any hour from any location with internet access."},
    {"id": 3, "statement": "City centres affected by the decline of retail have made no effort to adapt their empty shop spaces.", "answer": false, "evidence": "City centres have been forced to reinvent themselves, converting empty shop spaces into residential units, entertainment venues, and community facilities."},
    {"id": 4, "statement": "E-commerce has no environmental impact because it eliminates the need for large retail buildings.", "answer": false, "evidence": "The growth of packaging waste and the emissions from delivery vehicles represent significant challenges."},
    {"id": 5, "statement": "Returns from online shopping generate additional environmental costs through transportation and waste.", "answer": true, "evidence": "Returns generate additional transportation emissions and waste."}
