  "vocabulary_in_context": [
    {"id": 1, "sentence": "The buying and selling of goods over the internet — known as [BLANK] — has transformed retail globally since the 1990s.", "options": ["A) digital commerce", "B) e-commerce", "C) online retail", "D) internet trading"], "answer": "B", "explanation": "E-commerce is the specific term for buying and selling goods and services through the internet."},
    {"id": 2, "sentence": "Many long-established department stores have closed as [BLANK] sales have declined dramatically due to online competition.", "options": ["A) luxury", "B) high-street", "C) traditional", "D) physical"], "answer": "B", "explanation": "High street refers to traditional retail shops in town centres, which have declined as online shopping has grown."},
    {"id": 3, "sentence": "Companies offering regular delivery of household products in exchange for periodic payment use a [BLANK] model.", "options": ["A) subscription service", "B) delivery programme", "C) loyalty scheme", "D) membership plan"], "answer": "A", "explanation": "Subscription service describes the model of regular delivery in exchange for periodic payment."},
    {"id": 4, "sentence": "Delivery drivers working for short-term contracts without employment security are part of what is called the [BLANK].", "options": ["A) informal economy", "B) service industry", "C) gig economy", "D) digital workforce"], "answer": "C", "explanation": "The gig economy refers to work characterised by short-term contracts and freelance arrangements rather than permanent employment."}
  ],
  "critical_thinking": [
    {"id": 1, "question": "The passage describes both the convenience of online shopping and its negative consequences. On balance, is the rise of e-commerce good or bad for society? Give reasons.", "suggested_answer": "E-commerce brings genuine benefits: greater choice, lower prices, and convenience that saves time and improves access for people in rural areas or with limited mobility. However, the social costs are significant — the decline of high streets creates dead city centres that were previously social and community spaces, gig economy workers are exploited, and environmental costs of packaging and delivery are substantial. Whether the balance is positive depends partly on whether these costs are properly regulated and distributed. Currently, the convenience benefits flow mainly to consumers, while social and environmental costs are borne by workers and communities who receive little compensation."},
    {"id": 2, "question": "The passage raises concerns about gig economy workers who deliver online purchases. Should they be classified as employees rather than independent contractors? What are the arguments on both sides?", "suggested_answer": "Classifying delivery workers as employees would entitle them to minimum wage, sick pay, holiday pay, and legal protections. The argument for this classification is strong — many gig workers have limited freedom to work for competitors, follow strict company algorithms, and depend on a single platform for their income. The argument against is that employee status would raise costs for platforms, potentially reducing job opportunities, and that some workers genuinely value the flexibility of independent contracting. The most equitable solution may be an intermediate category — guaranteeing basic protections like minimum pay and accident insurance without requiring the full employment relationship."}
  ]
}$json$::jsonb
WHERE lesson_id = (
  SELECT l.id FROM english_lessons l
  JOIN english_modules m ON l.module_id = m.id
  JOIN english_courses c ON m.course_id = c.id
  WHERE c.title = 'B1 Intermediate' AND c.category = 'General English'
    AND m.order_index = 4 AND l.order_index = 4
) AND type = 'reading';

-- ── Lesson 5 ────────────────────────────────────────────────
UPDATE english_lesson_sections
SET content = $json${
  "title": "Fair Trade and Ethical Consumption",
  "text": "The fair trade movement emerged in the 1960s and 1970s as a response to concerns about the exploitation of producers in developing countries by global supply chains. Conventional commodity trade — particularly in products like coffee, cocoa, bananas, and cotton — has historically generated enormous profits for large corporations and retailers in wealthy countries while leaving farmers and workers in producing countries with minimal income, often below the cost of production. Fair trade organisations such as Fairtrade International certify products that meet standards for fair minimum prices, safe working conditions, environmental protection, and community investment. Consumers who buy certified fair trade products pay a small premium, a portion of which goes directly to producer cooperatives to invest in schools, healthcare, and infrastructure. The fair trade market has grown significantly. Fair trade certified products are now available in supermarkets worldwide, and major retailers have made fair trade commitments for key products like coffee and cocoa. However, critics have raised questions about the effectiveness of fair trade certification. Some research suggests that the benefits reach only a small proportion of workers in supply chains and that farmers in fair trade cooperatives do not always receive significantly higher incomes than non-certified farmers. Others argue that the system is primarily a marketing tool that allows consumers in wealthy countries to feel good about their purchases without requiring fundamental changes to trade structures. More radical approaches to ethical consumption argue that individual purchasing decisions, however well-intentioned, cannot substitute for systemic changes such as reforming international trade rules, ending agricultural subsidies that disadvantage developing country farmers, and ensuring that corporations operating globally are held accountable for the conditions in their entire supply chain.",
  "glossary": [
    {"term": "fair trade", "definition": "a trading partnership aiming to achieve greater equity for producers in developing countries", "translation": "справедливая торговля"},
    {"term": "cooperative", "definition": "a business or organisation owned and run jointly by its members for their mutual benefit", "translation": "кооператив"},
    {"term": "premium", "definition": "an additional amount paid above the standard price, often to ensure higher quality or ethical standards", "translation": "надбавка, премия"},
    {"term": "certification", "definition": "the process of officially confirming that something meets required standards", "translation": "сертификация"},
    {"term": "subsidy", "definition": "money paid by a government to support an industry or reduce costs for producers or consumers", "translation": "субсидия"},
    {"term": "accountability", "definition": "the fact of being responsible for actions and required to explain them", "translation": "подотчётность, ответственность"}
  ],
  "comprehension_questions": [
    {"id": 1, "question": "Why did the fair trade movement emerge according to the passage?", "options": ["A) To promote environmentally friendly farming practices worldwide", "B) As a response to concerns about the exploitation of producers in developing countries", "C) To create new markets for luxury products from poor countries", "D) To reduce the cost of imported goods for consumers in wealthy countries"], "answer": "B", "explanation": "The fair trade movement emerged as a response to concerns about the exploitation of producers in developing countries by global supply chains."},
    {"id": 2, "question": "What do fair trade certification standards require?", "options": ["A) Products must be made exclusively in developing countries", "B) Companies must donate ten percent of profits to charity", "C) Fair minimum prices, safe working conditions, environmental protection, and community investment", "D) Products must be produced using only organic farming methods"], "answer": "C", "explanation": "Fair trade standards cover fair minimum prices, safe working conditions, environmental protection, and community investment."},
    {"id": 3, "question": "How is the fair trade premium used according to the passage?", "options": ["A) It goes directly to individual farmers as higher wages", "B) It funds research into more productive farming techniques", "C) A portion goes to producer cooperatives to invest in schools, healthcare, and infrastructure", "D) It is used to cover the cost of certification and inspection"], "answer": "C", "explanation": "A portion of the premium goes directly to producer cooperatives to invest in schools, healthcare, and infrastructure."},
    {"id": 4, "question": "What criticism of fair trade certification does the passage mention?", "options": ["A) It raises consumer prices so much that demand falls significantly", "B) It only covers luxury products rather than essential goods", "C) Benefits may reach only a small proportion of supply chain workers and may primarily serve as a marketing tool", "D) Certification is controlled by large corporations that undermine its standards"], "answer": "C", "explanation": "Critics argue that benefits reach only a small proportion of workers and that fair trade is primarily a marketing tool allowing consumers to feel good without fundamental change."},
    {"id": 5, "question": "What does the passage describe as a more radical approach to ethical consumption?", "options": ["A) Refusing to buy any products made in developing countries", "B) Requiring all companies to obtain fair trade certification", "C) Systemic changes to international trade rules and corporate accountability", "D) Creating consumer cooperatives that buy directly from farmers"], "answer": "C", "explanation": "More radical approaches argue for systemic changes such as reforming trade rules and ensuring corporations are accountable for their entire supply chain."}
  ],
  "true_false_questions": [
    {"id": 1, "statement": "Conventional coffee and cocoa trade has historically provided high incomes to farmers in producing countries.", "answer": false, "evidence": "Conventional commodity trade has historically left farmers and workers in producing countries with minimal income, often below the cost of production."},
    {"id": 2, "statement": "Fair trade certified products are now available in supermarkets worldwide.", "answer": true, "evidence": "Fair trade certified products are now available in supermarkets worldwide."},
    {"id": 3, "statement": "All research confirms that fair trade farmers receive significantly higher incomes than non-certified farmers.", "answer": false, "evidence": "Some research suggests that farmers in fair trade cooperatives do not always receive significantly higher incomes than non-certified farmers."},
    {"id": 4, "statement": "The passage suggests that individual purchasing decisions alone are sufficient to transform international trade structures.", "answer": false, "evidence": "Individual purchasing decisions, however well-intentioned, cannot substitute for systemic changes such as reforming international trade rules."},
    {"id": 5, "statement": "Agricultural subsidies in wealthy countries can disadvantage developing country farmers.", "answer": true, "evidence": "More radical approaches argue for ending agricultural subsidies that disadvantage developing country farmers."}
  ],
  "vocabulary_in_context": [
    {"id": 1, "sentence": "Farmers in fair trade [BLANK] — organisations owned and run jointly by their members — can invest the premium in community projects.", "options": ["A) partnerships", "B) associations", "C) cooperatives", "D) companies"], "answer": "C", "explanation": "Cooperatives are businesses or organisations owned and run jointly by their members for mutual benefit."},
    {"id": 2, "sentence": "Consumers pay a small [BLANK] above the standard price for fair trade products, part of which supports producer communities.", "options": ["A) fee", "B) premium", "C) charge", "D) surcharge"], "answer": "B", "explanation": "Premium is the additional amount paid above the standard price for fair trade products."},
    {"id": 3, "sentence": "The process of officially confirming that a product meets fair trade standards is called [BLANK].", "options": ["A) verification", "B) auditing", "C) inspection", "D) certification"], "answer": "D", "explanation": "Certification is the process of officially confirming that something meets required standards."},
    {"id": 4, "sentence": "Governments pay [BLANK] to support domestic farmers, which can make it harder for developing country farmers to compete on world markets.", "options": ["A) grants", "B) subsidies", "C) benefits", "D) allowances"], "answer": "B", "explanation": "Subsidies are money paid by a government to support an industry or reduce costs — agricultural subsidies in wealthy countries can disadvantage developing country producers."}
  ],
  "critical_thinking": [
    {"id": 1, "question": "The passage describes fair trade as potentially a marketing tool rather than a fundamental solution. Is it better to support an imperfect system like fair trade or to wait for systemic change? Give your view.", "suggested_answer": "Supporting fair trade, even imperfectly, generates immediate improvements for some producers and builds consumer awareness of supply chain issues. Waiting for systemic change while doing nothing benefits no one. However, the risk is that buying fair trade satisfies the conscience without creating pressure for more significant reform. The most effective approach is to support fair trade as a partial measure while also advocating for stronger international trade rules, corporate accountability, and an end to subsidies that harm developing country producers. Individual action and systemic change are not alternatives — they complement each other."},
    {"id": 2, "question": "Should corporations operating globally be held legally accountable for conditions throughout their entire supply chain? What are the arguments for and against?", "suggested_answer": "The argument for holding corporations accountable throughout their supply chain is compelling. When a company profits from cheap labour in unsafe conditions by subcontracting to third parties, it is effectively benefiting from exploitation while avoiding responsibility for it. Supply chain accountability laws, such as those requiring human rights due diligence, make this responsibility explicit. The argument against is the practical difficulty of monitoring complex global supply chains and the potential that strict standards could push companies to source from fewer, more easily monitored suppliers, reducing opportunities for smaller producers. The goal should be meaningful accountability, not simply compliance theatre that adds bureaucracy without improving conditions."}
  ]
}$json$::jsonb
WHERE lesson_id = (
  SELECT l.id FROM english_lessons l
  JOIN english_modules m ON l.module_id = m.id
  JOIN english_courses c ON m.course_id = c.id
  WHERE c.title = 'B1 Intermediate' AND c.category = 'General English'
    AND m.order_index = 4 AND l.order_index = 5
) AND type = 'reading';

-- ── Lesson 6 ────────────────────────────────────────────────
UPDATE english_lesson_sections
SET content = $json${
  "title": "The Sharing Economy: Ownership vs Access",
  "text": "The sharing economy refers to a model of economic activity in which individuals share access to goods and services, typically facilitated by digital platforms. Companies such as Airbnb, which allows homeowners to rent out their properties to travellers, and Uber, which connects drivers with passengers, are among the most prominent examples. The sharing economy has grown enormously since the late 2000s, with total revenues in key sectors estimated in the hundreds of billions of dollars globally. Proponents argue that the sharing economy makes more efficient use of existing resources. Privately owned cars, for example, are stationary for approximately ninety-five percent of their lifespan. Sharing platforms allow these underutilised assets to generate economic value for their owners while providing convenient services for others. Property rental platforms allow homeowners to earn income from spare rooms or holiday properties. The environmental argument for sharing is that fewer goods need to be manufactured if more people share access to them. Critics, however, raise significant concerns. Short-term property rentals through platforms like Airbnb have been linked to rising housing costs in many cities, as landlords convert long-term rental properties to more profitable short-term lets. This reduces housing supply for permanent residents and contributes to affordability crises in popular cities. Ride-hailing services have been associated with increased urban congestion and adverse effects on traditional taxi industries. The gig workers who power these platforms often lack the employment protections and benefits that traditional employees receive. Increasingly, cities and governments are regulating sharing economy platforms, imposing limits on short-term rentals, requiring licensing of drivers, and demanding that platforms contribute to social security systems for their workers. The debate about the sharing economy reflects broader questions about how digital platforms should be governed in the public interest.",
  "glossary": [
    {"term": "sharing economy", "definition": "an economic model where goods and services are shared between individuals via digital platforms", "translation": "экономика совместного потребления"},
    {"term": "platform", "definition": "a digital service that connects buyers and sellers or providers and users", "translation": "платформа"},
    {"term": "underutilised", "definition": "not used to its full potential or capacity", "translation": "недостаточно используемый"},
    {"term": "short-term rental", "definition": "renting a property for a brief period, typically through online platforms like Airbnb", "translation": "краткосрочная аренда"},
    {"term": "congestion", "definition": "a situation where roads are so full of vehicles that movement is slowed or blocked", "translation": "пробки, заторы"},
    {"term": "gig workers", "definition": "people employed on short-term contracts or as independent contractors through digital platforms", "translation": "работники гиг-экономики"}
  ],
  "comprehension_questions": [
    {"id": 1, "question": "What is the sharing economy as described in the passage?", "options": ["A) A government programme to provide free services to low-income households", "B) An economic model where individuals share access to goods via digital platforms", "C) A cooperative system where businesses share profits with their employees", "D) An environmental initiative to reduce consumption by sharing ownership of goods"], "answer": "B", "explanation": "The sharing economy refers to a model of economic activity in which individuals share access to goods and services, facilitated by digital platforms."},
    {"id": 2, "question": "What percentage of their lifespan are privately owned cars stationary according to the passage?", "options": ["A) Around fifty percent", "B) Around seventy percent", "C) Around eighty percent", "D) Approximately ninety-five percent"], "answer": "D", "explanation": "Privately owned cars are stationary for approximately ninety-five percent of their lifespan."},
    {"id": 3, "question": "What problem has Airbnb been linked to in many cities?", "options": ["A) Reduced tourism and lower hotel occupancy rates", "B) Rising housing costs as landlords convert long-term rentals to short-term lets", "C) Increased noise and disturbance in residential neighbourhoods", "D) A decline in hotel standards due to reduced competition"], "answer": "B", "explanation": "Short-term property rentals have been linked to rising housing costs as landlords convert long-term rentals to more profitable short-term lets."},
    {"id": 4, "question": "What concerns about gig workers does the passage raise?", "options": ["A) They earn too much compared to traditional employees", "B) They lack the employment protections and benefits that traditional employees receive", "C) They create unfair competition for traditional taxi and hotel industries", "D) They pay too little tax on their income from platforms"], "answer": "B", "explanation": "Gig workers often lack the employment protections and benefits that traditional employees receive."},
    {"id": 5, "question": "How are governments responding to the growth of sharing economy platforms?", "options": ["A) By banning them entirely in most countries", "B) By providing tax incentives to encourage their growth", "C) By regulating them through licensing, rental limits, and social security contributions", "D) By creating government-owned alternatives to compete with private platforms"], "answer": "C", "explanation": "Cities and governments are imposing limits on short-term rentals, requiring licensing, and demanding social security contributions."}
  ],
