-- ── Lesson 7 ────────────────────────────────────────────────
UPDATE english_lesson_sections
SET content = $json${
  "title": "Financial Literacy: Managing Money in the Modern World",
  "text": "Financial literacy refers to the ability to understand and effectively manage personal finances, including budgeting, saving, borrowing, investing, and planning for the future. Despite its fundamental importance to individual well-being, financial education remains limited or absent in the school curricula of many countries. Research consistently shows that poor financial literacy is associated with higher levels of personal debt, inadequate retirement savings, and susceptibility to financial fraud. Budgeting is the foundation of sound financial management. A budget is a plan that tracks income and expenditure, helping individuals avoid spending more than they earn. The 50/30/20 rule — allocating fifty percent of income to needs, thirty percent to wants, and twenty percent to savings and debt repayment — is a widely recommended framework. However, applying such rules requires a stable income and a level of financial cushion that many people, particularly those in low-income situations, do not have. Understanding credit and debt is another essential component of financial literacy. Credit cards, loans, and mortgages can be valuable tools when used wisely, but their costs are often obscured by complex terms and conditions. Annual Percentage Rate (APR) is the most important figure to understand when comparing borrowing options — it represents the true yearly cost of credit including fees and interest. High-cost credit products such as payday loans can trap borrowers in cycles of debt. Investing — putting money to work in assets such as shares, bonds, or property to generate returns over time — is the primary mechanism by which individuals can build long-term wealth. Compound interest — earning returns on your previous returns — means that starting to invest early, even with small amounts, has a dramatically larger long-term impact than starting late with larger sums. Financial literacy education that begins in schools can help reduce inequality by giving all young people the knowledge to make informed financial decisions.",
  "glossary": [
    {"term": "financial literacy", "definition": "the ability to understand and manage personal finances effectively", "translation": "финансовая грамотность"},
    {"term": "budget", "definition": "a plan for income and expenditure over a given period", "translation": "бюджет"},
    {"term": "APR", "definition": "Annual Percentage Rate — the yearly cost of credit including interest and fees", "translation": "годовая процентная ставка"},
    {"term": "compound interest", "definition": "interest calculated on both the initial amount and the accumulated interest from previous periods", "translation": "сложные проценты"},
    {"term": "investment", "definition": "the act of putting money into assets with the expectation of generating future returns", "translation": "инвестиция"},
    {"term": "mortgage", "definition": "a loan secured against property, typically used to purchase a home", "translation": "ипотека"}
  ],
  "comprehension_questions": [
    {"id": 1, "question": "What does financial literacy include according to the passage?", "options": ["A) Only knowledge of how to save and invest money", "B) Understanding and managing budgeting, saving, borrowing, investing, and planning", "C) The ability to calculate tax and complete financial reporting", "D) Knowledge of stock markets and investment strategies"], "answer": "B", "explanation": "Financial literacy includes the ability to understand and effectively manage personal finances: budgeting, saving, borrowing, investing, and planning."},
    {"id": 2, "question": "According to the passage, what does poor financial literacy lead to?", "options": ["A) Reduced consumer spending and slower economic growth", "B) Higher taxes and reduced government revenue", "C) Higher personal debt, inadequate retirement savings, and susceptibility to fraud", "D) Lower levels of entrepreneurship and economic innovation"], "answer": "C", "explanation": "Poor financial literacy is associated with higher levels of personal debt, inadequate retirement savings, and susceptibility to financial fraud."},
    {"id": 3, "question": "What does the 50/30/20 rule recommend?", "options": ["A) Spending half your income, saving thirty percent, and investing twenty percent", "B) Allocating fifty percent to needs, thirty percent to wants, and twenty percent to savings and debt", "C) Spending fifty percent less than you earn and saving thirty percent for retirement", "D) Investing twenty percent in stocks, thirty percent in bonds, and fifty percent in property"], "answer": "B", "explanation": "The 50/30/20 rule allocates fifty percent to needs, thirty percent to wants, and twenty percent to savings and debt repayment."},
    {"id": 4, "question": "What is APR and why is it important?", "options": ["A) A government measure of average household income", "B) The annual percentage of income paid in taxes", "C) The true yearly cost of credit including fees and interest", "D) A credit score system used by banks to assess borrowers"], "answer": "C", "explanation": "APR represents the true yearly cost of credit including fees and interest — the most important figure when comparing borrowing options."},
    {"id": 5, "question": "What advantage of starting to invest early does the passage describe?", "options": ["A) Early investors receive preferential tax treatment from governments", "B) Compound interest means small early investments have a larger long-term impact than larger late investments", "C) Early investors can access better investment products with higher guaranteed returns", "D) Starting early allows investors to spread risk over more markets and asset types"], "answer": "B", "explanation": "Compound interest means that starting to invest early, even with small amounts, has a dramatically larger long-term impact than starting late with larger sums."}
  ],
  "true_false_questions": [
    {"id": 1, "statement": "Financial education is well-established in the school curricula of most countries.", "answer": false, "evidence": "Financial education remains limited or absent in the school curricula of many countries."},
    {"id": 2, "statement": "A budget is a plan that helps individuals track income and avoid spending more than they earn.", "answer": true, "evidence": "A budget is a plan that tracks income and expenditure, helping individuals avoid spending more than they earn."},
    {"id": 3, "statement": "The 50/30/20 rule is equally practical for all income levels.", "answer": false, "evidence": "Applying such rules requires a stable income and a level of financial cushion that many people, particularly those in low-income situations, do not have."},
    {"id": 4, "statement": "Payday loans are recommended in the passage as an affordable form of credit.", "answer": false, "evidence": "High-cost credit products such as payday loans can trap borrowers in cycles of debt."},
    {"id": 5, "statement": "Compound interest means earning returns on both the initial investment and previously accumulated returns.", "answer": true, "evidence": "Compound interest — earning returns on your previous returns — means that starting to invest early has a dramatically larger long-term impact."}
